156	      expect(
157	        quote({
158	          customer: { yearsWithMHPCO: 2 },
159	          items: [{ type: "rune", enchantment: 5 }],
160	        }),
161	      ).toBe(33);
162	    });
163	  });
164	
165	  describe("quote — integration examples", () => {
