168	        quote({
169	          customer: { yearsWithMHPCO: 0, previousContracts: 0 },
170	          items: [
171	            { type: "sword", material: "steel", enchantment: 3, cursed: true },
172	          ],
173	        }),
174	      ).toBe(165);
