178	
179	  describe("claim — standard reimbursement and deductible", () => {
180	    it.todo("pays 400 G for a steel sword enchantment 3 with 500 G damage (full minus 100 deductible)");
181	    it.todo("pays 100 G for a rune with 200 G damage (full minus 100 deductible)");
182	    it.todo("applies the 100 G deductible once per damaged item (sword 500 + amulet 300 → 600)");
183	  });
184	
185	  describe("claim — special clauses", () => {
186	    it.todo("reimburses 50% before deductible for a steel sword at enchantment 9 with 1000 G damage (→ 400)");
187	    it.todo("fully reimburses before deductible for a dragon sword at enchantment 5 with 800 G damage (→ 700)");
188	    it.todo("applies the 50% rule over dragon material for a dragon sword at enchantment 9 with 1000 G damage (→ 400)");
189	    it.todo("applies the high-enchantment clause for a dragon sword at exactly enchantment 8 with 1000 G damage (→ 400)");
190	  });
191	
192	  describe("claim — cap", () => {
193	    it.todo("caps total payout at twice the unmodified insurance sum");
194	    it.todo("reduces a claim to the remaining cap and reports remainingCap across successive claims (1500 → 1400 then 600)");
195	  });
196	
197	  describe("claim — rounding", () => {
198	    it.todo("rounds the final payout down to whole G (350.5 → 350)");
199	  });
200	});
