1	export interface QuoteInput {
2	  customer?: { yearsWithMHPCO: number; previousContracts?: number };
3	  items: { type: string; cursed?: boolean; enchantment?: number }[];
4	}
5	
6	const PROCESSING_FEE = 5;
7	
8	const BLOCK_SIZE = 3;
9	const BLOCK_PRICE = 60;
10	
11	const CURSE_SURCHARGE_RATE = 0.5;
12	
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	
16	const LOYALTY_MINIMUM_YEARS = 2;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	
19	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
20	
21	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
22	
23	// Premiums are rounded up to whole G, in MHPCO's favour.
24	const roundUpToWholeG = (amount: number): number => Math.ceil(amount);
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	export function quote(input: QuoteInput): number {
36	  const countsByType: Record<string, number> = {};
37	  for (const item of input.items) {
38	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
39	  }
40	
41	  let basePremiumTotal = 0;
42	  for (const type of Object.keys(countsByType)) {
43	    const count = countsByType[type];
44	    if (count === BLOCK_SIZE) {
45	      basePremiumTotal += BLOCK_PRICE;
46	    } else {
47	      basePremiumTotal += count * BASE_PREMIUMS[type];
48	    }
49	  }
50	
51	  const isFirstInsurance = input.customer?.previousContracts === 0;
52	
53	  let surchargeTotal = 0;
54	  for (const item of input.items) {
55	    if (item.cursed) {
56	      surchargeTotal += BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE;
57	    }
58	    if (
59	      item.enchantment !== undefined &&
60	      item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
61	    ) {
62	      surchargeTotal +=
63	        BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
64	    }
65	    if (isFirstInsurance) {
66	      surchargeTotal +=
67	        BASE_PREMIUMS[item.type] * FIRST_INSURANCE_SURCHARGE_RATE;
68	    }
69	  }
70	
71	  const isLoyal =
72	    (input.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_MINIMUM_YEARS;
73	  const isFollowUp = (input.customer?.previousContracts ?? 0) >= 1;
74	
75	  const loyaltyDiscount = isLoyal ? basePremiumTotal * LOYALTY_DISCOUNT_RATE : 0;
76	  const followUpDiscount = isFollowUp
77	    ? basePremiumTotal * FOLLOW_UP_DISCOUNT_RATE
78	    : 0;
79	
80	  const rawPremium =
81	    basePremiumTotal -
82	    loyaltyDiscount -
83	    followUpDiscount +
84	    surchargeTotal +
85	    PROCESSING_FEE;
86	
87	  return roundUpToWholeG(rawPremium);
88	}
89	
90	export function claim(): number {
91	  return undefined as unknown as number;
92	}
